output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?foundingYear WHERE {
  {
    SELECT ?iranianCity WHERE {
      ?iranianCity wdt:P31 wd:Q515 ; wdt:P17 wd:Q794 ; wdt:P1082 ?pop . MINUS {
        ?iranianCity wdt:P576 ?dissolved .
      }
    }
    ORDER BY DESC(?pop)
    LIMIT 1
    OFFSET 23
  }
  {
    ?iranianCity wdt:P190 ?arabCity .
  } UNION {
    ?arabCity wdt:P190 ?iranianCity .
  }
  ?arabCity wdt:P17 ?country .
  ?country wdt:P463 wd:Q40828 .
  ?arabCity wdt:P571 ?foundingYear .
}

